abstract class Visitor {
  + {abstract} visit(Expression& expr)
}

class Printer {
  - stringstream oss
  + visit(Expression& expr)\n  if (auto de = dynamic_cast<Value&>(e))\n      oss << de.value\n  else if (auto ae = dynamic_cast<Addition&>(e))\n      visit(ae.left)\n      oss << "+"\n      visit(ae.right)\n  else if...
}

class Evaluator {
  - int total
  + visit(Expression& expr)
}

Value --|> Expression
Addition --|> Expression
Multiplication --|> Expression

Printer ..|> Visitor
Evaluator --|> Visitor

Printer ..> Value
Printer ..> Addition
Printer ..> Multiplication

@enduml
